/// <summary>
/// Extension of endPost to trigger Business Events after journal posting is finalized.
/// </summary>
protected void endPost()
{

    next endPost();


    Common journalHeader = this.parmJournalTable();


    if (journalHeader is VendInvoiceJour)
    {
        VendInvoiceJour invoiceJour = journalHeader as VendInvoiceJour;


        PurchInvoiceBusinessEvent::newFromVendInvoiceJour(invoiceJour).send();
    }
}
